		protected QueryResultSummary evaluate(LmdbBenchmarkQueryPlan plan) {
			long rowCount = 0L;
			Long countBindingValue = null;
			try (CloseableIteration<BindingSet> result = plan.evaluate()) {
				while (result.hasNext()) {
					BindingSet bindings = result.next();
					rowCount++;
					if (expectedCountBindingValue.isPresent()) {
						if (rowCount > 1) {
							throw new IllegalStateException("Expected exactly one count row for "
									+ queryDescription() + " but saw at least " + rowCount + " rows");
						}
						countBindingValue = countBindingValue(bindings);
					}
				}
			}
			return new QueryResultSummary(rowCount, countBindingValue);
		}

		private Long countBindingValue(BindingSet bindings) {
			var value = bindings.getValue(COUNT_BINDING_NAME);
			if (value == null) {
				return null;
			}
			if (value instanceof Literal literal) {
				return literal.longValue();
			}
			throw new IllegalStateException("Unexpected aggregate binding type for " + COUNT_BINDING_NAME + ": "
					+ value);
		}

		protected void assertExpectedResult(QueryResultSummary result) {
			if (result.rowCount != expectedRows) {
				throw new IllegalStateException("Unexpected result row count for " + queryDescription() + ": expected "
						+ expectedRows + " but got " + result.rowCount);
			}
			if (expectedCountBindingValue.isPresent()) {
				if (result.countBindingValue == null) {
					throw new IllegalStateException("Expected literal ?" + COUNT_BINDING_NAME + " binding for "
							+ queryDescription() + " but got null");
				}
				long expectedValue = expectedCountBindingValue.getAsLong();
				if (result.countBindingValue != expectedValue) {
					throw new IllegalStateException("Unexpected ?" + COUNT_BINDING_NAME + " binding for "
							+ queryDescription() + ": expected " + expectedValue + " but got "
							+ result.countBindingValue);
				}
			}
		}

		protected long benchmarkResult(QueryResultSummary result) {
			return expectedCountBindingValue.isPresent() ? result.countBindingValue : result.rowCount;
		}

		private String queryDescription() {
			String description = themeName + " query " + z_queryIndex + " ("
					+ ThemeQueryCatalog.benchmarkQueryFor(theme, z_queryIndex).getName() + ")";
			String variant = queryVariantOrDefault(queryVariant);
			if (!QUERY_VARIANT_FILTER.equals(variant)) {
				description += " [" + variant + "]";
			}
			return description;
		}

		private String variantFileSuffix() {
			String variant = queryVariantOrDefault(queryVariant);
			if (QUERY_VARIANT_FILTER.equals(variant)) {
				return "";
			}
			return "-" + variant.replaceAll("[^A-Za-z0-9._-]", "_");
		}

		private static String queryForVariant(Theme theme, int queryIndex, String queryVariant) {
			String variant = queryVariantOrDefault(queryVariant);
			if (QUERY_VARIANT_FILTER.equals(variant)) {
				return ThemeQueryCatalog.queryFor(theme, queryIndex);
			}
			if (theme == Theme.MEDICAL_RECORDS && queryIndex == 7) {
				if (QUERY_VARIANT_FILTER_IN.equals(variant)) {
					return medicalQ7FilterInQuery();
				}
				if (QUERY_VARIANT_VALUES_TOP_TYPE_CODE.equals(variant)) {
					return medicalQ7ValuesTopTypeCodeQuery();
				}
				if (QUERY_VARIANT_TYPE_VALUES_CODE.equals(variant)) {
					return medicalQ7TypeValuesCodeQuery();
				}
				if (QUERY_VARIANT_VALUES_CODE_TYPE.equals(variant)) {
					return medicalQ7ValuesCodeTypeQuery();
				}
				if (QUERY_VARIANT_TYPE_ANTI_VALUES_CODE.equals(variant)) {
					return medicalQ7TypeAntiValuesCodeQuery();
				}
				if (QUERY_VARIANT_VALUES_CODE_ANTI_TYPE.equals(variant)) {
					return medicalQ7ValuesCodeAntiTypeQuery();
				}
			}
			if (theme == Theme.SOCIAL_MEDIA && queryIndex == 5) {
				if (QUERY_VARIANT_SOCIAL_Q5_NAME_BEFORE_UNION.equals(variant)) {
					return socialQ5NameBeforeUnionQuery();
				}
				if (QUERY_VARIANT_SOCIAL_Q5_BRANCH_LOCAL_NAME.equals(variant)) {
					return socialQ5BranchLocalNameQuery();
				}
				if (QUERY_VARIANT_SOCIAL_Q5_FILTER_EXISTS_NAME.equals(variant)) {
					return socialQ5FilterExistsNameQuery();
				}
			}
			throw new IllegalArgumentException("Unsupported ThemeQueryPlanRunBenchmark queryVariant=" + queryVariant
					+ " for " + theme + " q" + queryIndex);
		}

		private static String queryVariantOrDefault(String queryVariant) {
			if (queryVariant == null || queryVariant.isBlank()) {
				return QUERY_VARIANT_FILTER;
			}
			String normalized = queryVariant.trim();
			if ("catalog".equals(normalized) || "medical-q7-filter".equals(normalized)) {
				return QUERY_VARIANT_FILTER;
			}
			if ("values".equals(normalized) || "medical-q7-values".equals(normalized)) {
				return QUERY_VARIANT_VALUES_TOP_TYPE_CODE;
			}
			if ("in".equals(normalized) || "medical-q7-filter-in".equals(normalized)) {
				return QUERY_VARIANT_FILTER_IN;
			}
			if ("type-not-exists-values-code".equals(normalized)
					|| "medical-q7-type-anti-values-code".equals(normalized)) {
				return QUERY_VARIANT_TYPE_ANTI_VALUES_CODE;
			}
			if ("values-code-not-exists-type".equals(normalized)
					|| "medical-q7-values-code-anti-type".equals(normalized)) {
				return QUERY_VARIANT_VALUES_CODE_ANTI_TYPE;
			}
			if ("q5-name-before-union".equals(normalized)) {
				return QUERY_VARIANT_SOCIAL_Q5_NAME_BEFORE_UNION;
			}
			if ("q5-branch-local-name".equals(normalized)) {
				return QUERY_VARIANT_SOCIAL_Q5_BRANCH_LOCAL_NAME;
			}
			if ("q5-filter-exists-name".equals(normalized) || "q5-exists-name".equals(normalized)) {
				return QUERY_VARIANT_SOCIAL_Q5_FILTER_EXISTS_NAME;
			}
			return normalized;
		}

		private static String medicalQ7FilterInQuery() {
			return String.join("\n",
					"PREFIX med: <http://example.com/theme/medical/>",
					"PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>",
					"",
					"SELECT (COUNT(DISTINCT ?med) AS ?count) WHERE {",
					"  ?med a med:Medication .",
					"  ?med med:code ?code .",
					"  FILTER(?code IN (\"MED-1000\", \"MED-1001\"))",
					"  FILTER EXISTS { ?patient med:hasMedication ?med . }",
					"  MINUS { ?med med:dosage ?dose . FILTER(CONTAINS(LCASE(STR(?dose)), \"x\")) }",
					"}");
		}

